import React from 'react';
import './App.css';

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>LinkGrow - Editor Multimídia</h1>
        <p>
          Bem-vindo ao LinkGrow, uma plataforma avançada para gerenciamento de conteúdo para redes sociais.
        </p>
        <a
          className="App-link"
          href="/dashboard"
          rel="noopener noreferrer"
        >
          Acessar o Dashboard
        </a>
      </header>
    </div>
  );
}

export default App;
